   "source": [
    "# -------------------------------\n",
    "# 1. Data Cleaning\n",
    "# -------------------------------\n",
    "\n",
    "# =========================\n",
    "# Data Overview\n",
    "# =========================\n",
    "data_overview <- function(df) {\n",
    "  \n",
    "  cat(\"\\n--- Missing Values ---\\n\")\n",
    "  missing <- colSums(is.na(df))\n",
    "  print(missing)\n",
    "  \n",
    "  if(sum(missing) > 0){\n",
    "    missing_df <- missing[missing > 0]\n",
    "    \n",
    "    barplot(missing_df,\n",
    "            main = \"Missing Values per Column\",\n",
    "            las = 2,\n",
    "            col = \"steelblue\")\n",
    "  }\n",
    "  \n",
    "  cat(\"\\n--- Duplicate Rows ---\\n\")\n",
    "  print(sum(duplicated(df)))\n",
    "  \n",
    "  return(df)\n",
    "}\n",
    "\n",
    "# =========================\n",
    "# Handle Missing Values\n",
    "# =========================\n",
    "handle_missing_values <- function(df) {\n",
    "  \n",
    "  df[df %in% c(\"NA\",\"N/A\",\"null\",\"?\",\"\",\"None\",\"nan\",\"NaN\",\" \")] <- NA\n",
    "  \n",
    "  threshold <- nrow(df) * 0.5\n",
    "  df <- df[, colSums(is.na(df)) < threshold]\n",
    "  \n",
    "  df <- df %>% mutate(across(everything(), ~ type.convert(., as.is = TRUE)))\n",
    "  \n",
    "  num_cols <- names(df)[sapply(df, is.numeric)]\n",
    "  cat_cols <- names(df)[sapply(df, is.character)]\n",
    "  \n",
    "  for(col in num_cols){\n",
    "    df[[col]][is.na(df[[col]])] <- mean(df[[col]], na.rm = TRUE)\n",
    "  }\n",
    "  \n",
    "  for(col in cat_cols){\n",
    "    mode_val <- names(sort(table(df[[col]]), decreasing = TRUE))[1]\n",
    "    \n",
    "    if(length(mode_val) == 0){\n",
    "      df[[col]][is.na(df[[col]])] <- \"Unknown\"\n",
    "    } else {\n",
    "      df[[col]][is.na(df[[col]])] <- mode_val\n",
    "    }\n",
    "  }\n",
    "  \n",
    "  df <- na.omit(df)\n",
    "  \n",
    "  cat(\"Remaining missing values:\", sum(is.na(df)), \"\\n\")\n",
    "  \n",
    "  return(df)\n",
    "}\n",
    "\n",
    "# =========================\n",
    "# Remove Duplicates\n",
    "# =========================\n",
    "remove_duplicates <- function(df){\n",
    "  df <- distinct(df)\n",
    "  cat(\"Duplicates removed.\\n\")\n",
    "  return(df)\n",
    "}\n",
    "\n",
    "# =========================\n",
    "# Fix Data Types\n",
    "# =========================\n",
    "fix_data_types <- function(df){\n",
    "  df <- df %>% mutate(across(everything(), ~ type.convert(., as.is = TRUE)))\n",
    "  cat(\"Data types fixed.\\n\")\n",
    "  return(df)\n",
    "}\n",
    "\n",
    "# =========================\n",
    "# Remove Outliers (IQR)\n",
    "# =========================\n",
    "remove_outliers <- function(df){\n",
    "  \n",
    "  num_cols <- names(df)[sapply(df, is.numeric)]\n",
    "  mask <- rep(TRUE, nrow(df))\n",
    "  \n",
    "  for(col in num_cols){\n",
    "    Q1 <- quantile(df[[col]], 0.25, na.rm = TRUE)\n",
    "    Q3 <- quantile(df[[col]], 0.75, na.rm = TRUE)\n",
    "    IQR <- Q3 - Q1\n",
    "    \n",
    "    lower <- Q1 - 1.5 * IQR\n",
    "    upper <- Q3 + 1.5 * IQR\n",
    "    \n",
    "    mask <- mask & (df[[col]] >= lower & df[[col]] <= upper)\n",
    "  }\n",
    "  \n",
    "  df_clean <- df[mask, ]\n",
    "  \n",
    "  cat(\"Outliers removed. Remaining rows:\", nrow(df_clean), \"\\n\")\n",
    "  return(df_clean)\n",
    "}\n",
    "\n",
    "# =========================\n",
    "# Visualize Outliers\n",
    "# =========================\n",
    "visualize_outliers <- function(df){\n",
    "  \n",
    "  num_cols <- names(df)[sapply(df, is.numeric)]\n",
    "  \n",
    "  # Boxplot\n",
    "  boxplot(df[num_cols],\n",
    "          las = 2,\n",
    "          main = \"Boxplot of Numeric Features\")\n",
    "  \n",
    "  # Histogram\n",
    "  df[num_cols] %>% \n",
    "    pivot_longer(cols = everything()) %>%\n",
    "    ggplot(aes(value)) +\n",
    "    geom_histogram(bins = 30, fill = \"steelblue\") +\n",
    "    facet_wrap(~name, scales = \"free\") +\n",
    "    ggtitle(\"Histograms\")\n",
    "  \n",
    "  # Correlation Heatmap\n",
    "  corr <- cor(df[num_cols])\n",
    "  corrplot(corr, method = \"color\")\n",
    "}\n",
    "\n",
    "# =========================\n",
    "# Normalize Data\n",
    "# =========================\n",
    "normalize_data <- function(df){\n",
    "  \n",
    "  num_cols <- names(df)[sapply(df, is.numeric)]\n",
    "  \n",
    "  df[num_cols] <- lapply(df[num_cols], function(x){\n",
    "    denom <- max(x) - min(x)\n",
    "    if(denom == 0) denom <- 1\n",
    "    (x - min(x)) / denom\n",
    "  })\n",
    "  \n",
    "  cat(\"Data normalized safely.\\n\")\n",
    "  return(df)\n",
    "}\n",
    "\n",
    "# =========================\n",
    "# Full Pipeline\n",
    "# =========================\n",
    "clean_data_pipeline <- function(df, save_path = NULL){\n",
    "  \n",
    "  df <- data_overview(df)\n",
    "  df <- handle_missing_values(df)\n",
    "  df <- remove_duplicates(df)\n",
    "  df <- fix_data_types(df)\n",
    "  \n",
    "  cat(\"Before removing outliers:\\n\")\n",
    "  visualize_outliers(df)\n",
    "  \n",
    "  df <- remove_outliers(df)\n",
    "  \n",
    "  cat(\"After removing outliers:\\n\")\n",
    "  visualize_outliers(df)\n",
    "  \n",
    "  df <- normalize_data(df)\n",
    "  \n",
    "  if(!is.null(save_path)){\n",
    "    write.csv(df, save_path, row.names = FALSE)\n",
    "    cat(\"Cleaned data saved to\", save_path, \"\\n\")\n",
    "  }\n",
    "  \n",
    "  return(df)\n",
    "}\n",
    "\n",
    "# =========================\n",
    "# Run Pipeline\n",
    "# =========================\n",
    "\n",
    "cleaned_df <- clean_data_pipeline(data, \"cleaned_data.csv\")\n",
    "\n",
    "head(cleaned_df)"
   ]
  },
