   "source": [
    "conversion_rate <- function(data, feature) {\n",
    "  data %>%\n",
    "    group_by(.data[[feature]]) %>%\n",
    "    summarise(\n",
    "      total = n(),\n",
    "      conversions = sum(y),\n",
    "      conversion_rate = mean(y)\n",
    "    ) %>%\n",
    "    arrange(desc(conversion_rate))\n",
    "}"
   ]
  },
